    async def get_album(self, album_id: str, **kwargs: Any) -> Optional[GetAlbumAlbum]:
        query = gql("""
            query GetAlbum($albumId: String!) {
              album(albumId: $albumId) {
                ...AlbumFields
                duration
                tracksCount
                discsCount
                isTakenDown
                fallback {
                  id
                  displayTitle
                }
                tracks(first: 50) {
                  edges {
                    cursor
                    node {
                      ...TrackFields
                    }
                  }
                  pageInfo {
                    ...PageInfoFields
                  }
                }
                url {
                  __typename
                  ... on Url {
                    webUrl
                  }
                }
              }
            }

            fragment AlbumFields on Album {
              id
              displayTitle
              type
              cover {
                id
                urls(pictureRequest: {width: 264, height: 264})
              }
              contributors(first: 5, roles: [MAIN]) {
                edges {
                  node {
                    ... on Artist {
                      id
                      name
                    }
                  }
                }
              }
              releaseDate
              isExplicit
              isFavorite
              fansCount
              label
              copyright
            }

            fragment PageInfoFields on PageInfo {
              hasNextPage
              endCursor
            }

            fragment TrackFields on Track {
              id
              title
              ISRC
              diskInfo {
                diskNumber
                trackNumber
              }
              duration
              isExplicit
              isFavorite
              popularity
              album {
                id
                displayTitle
                cover {
                  id
                  urls(pictureRequest: {width: 264, height: 264})
                }
              }
              contributors(first: 10, roles: [MAIN, FEATURED]) {
                edges {
                  roles
                  node {
                    ... on Artist {
                      id
                      name
                    }
                  }
                }
              }
            }
            """)
        variables: dict[str, object] = {"albumId": album_id}
        response = await self.execute(
            query=query, operation_name="GetAlbum", variables=variables, **kwargs
        )
        data = self.get_data(response)
        return GetAlbum.model_validate(data).album

